from pydantic import BaseModel, validator

class RawOrder(BaseModel):
    order_id: str
    user_id: int
    total: float

    @validator("total")
    def total_must_be_positive(cls, v):
        if v <= 0:
            raise ValueError(f"Order total must be positive, got {v}")
        return v

def validate_orders(records):
    for raw in records:
        try:
            yield RawOrder(**raw).dict()
        except Exception as e:
            logging.error(f"Validation failed: {e} | record={raw}")
